            const maxLines = Math.max(nCustLines, nAddrLines, nItemLines);
            // 4.5mm per line approx + padding
            const rowHeight = (maxLines * 4.5) + 3; 

            // Check Page Break
            if (currentY + rowHeight > pageH - 10) {
                doc.addPage();
                pageIndex++;
                currentY = drawHeader(pageIndex);
            }

            // --- DRAW CONTENT ---
            const textY = currentY + 4;

