export const pdfService = {
    // --- MODE 1: COMPACT LIST (2-COLUMN EXCEL STYLE - HIGH DENSITY) ---
    // Target: 45-50 orders per page
    generateCompactList: async (orders: Order[], batchId: string) => {
        const doc = new jsPDF({ orientation: 'p', unit: 'mm', format: 'a4' });

        const binaryFont = await fetchFont();
        let fontName = 'helvetica';
        if (binaryFont) {
            const fontFileName = 'Roboto.ttf';
            doc.addFileToVFS(fontFileName, binaryFont);
            doc.addFont(fontFileName, 'Roboto', 'normal');
            doc.addFont(fontFileName, 'Roboto', 'bold');
            doc.addFont(fontFileName, 'Roboto', 'italic');
            doc.setFont('Roboto');
            fontName = 'Roboto';
        }

        // --- PAGE CONFIG ---
        const pageW = 210;
        const pageH = 297;
        const margin = 4; // Minimal margin
        const headerH = 12;
        const colGap = 2; // Minimal gap between main columns

        // Width of one main column (Half page)
        const mainColW = (pageW - (margin * 2) - colGap) / 2; // ~100mm

        // --- SUB-COLUMN WIDTHS (Total ~100mm) ---
        // STT | Khách | ĐC | SĐT | Hàng | Note/COD
        const wIdx = 6;
        const wCust = 22;
        const wAddr = 24; 
        const wPhone = 16;
        const wItem = 22;
        const wNote = mainColW - wIdx - wCust - wAddr - wPhone - wItem; // ~10mm

        // Helper for X coords relative to column start
        const getX = (startX: number) => ({
            idx: startX,
            cust: startX + wIdx,
            addr: startX + wIdx + wCust,
            phone: startX + wIdx + wCust + wAddr,
            item: startX + wIdx + wCust + wAddr + wPhone,
            note: startX + wIdx + wCust + wAddr + wPhone + wItem
        });

        let currentY = headerH + 3;
        const fontSize = 7; // Small font for high density
        const rowPadding = 1; // 1mm padding top/bottom
        const lineHeight = 3; // Approx height per line of text

        // Data Prep
        let totalAmount = 0;
        const itemSummary: Record<string, number> = {};

        const validOrders = orders.filter(o => o.status !== OrderStatus.CANCELLED);
        validOrders.forEach(o => {
            totalAmount += o.totalPrice;
            o.items.forEach(item => {
                const name = item.name.trim();
                if(name) itemSummary[name] = (itemSummary[name] || 0) + item.quantity;
            });
        });

        const drawPageHeader = (pageNo: number) => {
            doc.setFillColor(255, 255, 255);
            doc.rect(0, 0, pageW, headerH, 'F');

            // Doc Title
            doc.setFontSize(10);
            doc.setFont(fontName, 'bold');
            doc.setTextColor(0, 0, 0);
            doc.text(`${batchId} - ${new Date().toLocaleDateString('vi-VN')}`, margin, 5);

            doc.setFontSize(7);
            doc.setFont(fontName, 'normal');
            doc.text(`Trang ${pageNo}`, pageW - margin, 5, { align: 'right' });

            // --- TABLE HEADERS (BLACK BACKGROUND) ---
            const hY = 7;
            const hHeight = 5; // Very slim header

            const drawColHeader = (startX: number) => {
                doc.setFillColor(0, 0, 0);
                doc.rect(startX, hY, mainColW, hHeight, 'F');
                doc.setTextColor(255, 255, 255);
                doc.setFontSize(6); // Tiny header font
                doc.setFont(fontName, 'bold');

                const x = getX(startX);
                // Dividers (White)
                doc.setDrawColor(255, 255, 255);
                doc.setLineWidth(0.2);
                doc.line(x.cust, hY, x.cust, hY + hHeight);
                doc.line(x.addr, hY, x.addr, hY + hHeight);
                doc.line(x.phone, hY, x.phone, hY + hHeight);
                doc.line(x.item, hY, x.item, hY + hHeight);
                doc.line(x.note, hY, x.note, hY + hHeight);

                // Text centered vertically
                const ty = hY + 3.5;
                doc.text("STT", x.idx + 1, ty);
                doc.text("KHÁCH HÀNG", x.cust + 1, ty);
                doc.text("ĐỊA CHỈ", x.addr + 1, ty);
                doc.text("SĐT", x.phone + 1, ty);
                doc.text("HÀNG HÓA", x.item + 1, ty);
                doc.text("GHI CHÚ", x.note + 1, ty);
            };

            drawColHeader(margin);
            drawColHeader(margin + mainColW + colGap);

            doc.setTextColor(0, 0, 0); // Reset to black
            return hY + hHeight;
        };

        let pageIndex = 1;
        currentY = drawPageHeader(pageIndex); 

        // Iterate in pairs (Left and Right) for optimal parallel layout
        for (let i = 0; i < validOrders.length; i += 2) {
            const oLeft = validOrders[i];
            const oRight = validOrders[i + 1];

            // --- PREPARE CONTENT & CALCULATE HEIGHT ---
            const prepContent = (o: Order, wC: number, wA: number, wP: number, wI: number, wN: number) => {
                if (!o) return { lines: 0, cust: [], addr: [], phone: '', items: [], note: [] };

                doc.setFontSize(fontSize);
                doc.setFont(fontName, 'bold');
                const cust = doc.splitTextToSize(o.customerName, wC - 1);

                doc.setFont(fontName, 'normal');
                // Aggressive address split
                const addr = doc.splitTextToSize(o.address.replace(/^(số|đường|hẻm|ngõ)\s/gi, ''), wA - 1);

                const itemsStr = o.items.map(it => `${it.name}${it.quantity > 1 ? `(${it.quantity})` : ''}`).join(', ');
                const items = doc.splitTextToSize(itemsStr, wI - 1);

                let noteText = "";
                const isPaid = o.paymentVerified || o.paymentMethod === PaymentMethod.PAID;
                if (o.paymentMethod === PaymentMethod.CASH && !isPaid) {
                    noteText = `${new Intl.NumberFormat('vi-VN').format(o.totalPrice/1000)}k`; // Compact price (120k)
                } else if (isPaid) {
                    noteText = "CK";
                }
                if (o.notes) noteText += `/${o.notes}`;
                const note = doc.splitTextToSize(noteText, wN - 1);

                // Phone logic
                const phone = o.customerPhone.replace('+84', '0').replace(/\s/g, '').substring(0, 10);

                const lines = Math.max(cust.length, addr.length, items.length, note.length);
                return { lines, cust, addr, phone, items, note };
            };

            const left = prepContent(oLeft, wCust, wAddr, wPhone, wItem, wNote);
            const right = prepContent(oRight, wCust, wAddr, wPhone, wItem, wNote);

            // Row Height is max of left or right
            const maxLines = Math.max(left.lines, right.lines);
            // Height = (lines * lineHeight) + (padding * 2)
            // Ensure minimum height of 6mm for very short rows
            const rowHeight = Math.max(6, (maxLines * lineHeight) + (rowPadding * 2));

            // Check Page Break
            if (currentY + rowHeight > pageH - 5) {
                doc.addPage();
                pageIndex++;
                currentY = drawPageHeader(pageIndex);
            }

            // --- DRAW FUNCTION ---
            const drawRow = (startX: number, data: any, order: Order, idx: number) => {
                if (!order) return;
                const x = getX(startX);
                const y = currentY;

                // Borders
                doc.setDrawColor(0, 0, 0);
                doc.setLineWidth(0.1);
                doc.rect(startX, y, mainColW, rowHeight); // Box

                // Vertical lines
                doc.line(x.cust, y, x.cust, y + rowHeight);
                doc.line(x.addr, y, x.addr, y + rowHeight);
                doc.line(x.phone, y, x.phone, y + rowHeight);
                doc.line(x.item, y, x.item, y + rowHeight);
                doc.line(x.note, y, x.note, y + rowHeight);

                // Text
                const textY = y + rowPadding + 2.5; // Baseline approx

                doc.setFontSize(fontSize);
                doc.setFont(fontName, 'normal'); // Reset

                // 1. STT
                doc.text(`${idx + 1}`, x.idx + 1, textY);

                // 2. Cust (Bold)
                doc.setFont(fontName, 'bold');
                doc.text(data.cust, x.cust + 1, textY);

                // 3. Addr
                doc.setFont(fontName, 'normal');
                doc.text(data.addr, x.addr + 1, textY);

                // 4. Phone
                doc.text(data.phone, x.phone + 1, textY);

                // 5. Items
                doc.text(data.items, x.item + 1, textY);

                // 6. Note (Bold Red-ish logic handled via text, just bold here)
                doc.setFont(fontName, 'bold');
                doc.text(data.note, x.note + 1, textY);
            };

            // Draw Left
            drawRow(margin, left, oLeft, i);
            // Draw Right
            drawRow(margin + mainColW + colGap, right, oRight, i + 1);

            currentY += rowHeight;
        }

        // --- SUMMARY FOOTER ---
        // If space left is small, new page
        if (pageH - currentY < 15) {
            doc.addPage();
            currentY = 10;
        } else {
            currentY += 2;
        }

        doc.setFontSize(9);
        doc.setFont(fontName, 'bold');
        doc.text(`TỔNG KẾT: ${new Intl.NumberFormat('vi-VN').format(totalAmount)}đ`, margin, currentY + 5);

        // Compact Item Summary
        doc.setFontSize(7);
        doc.setFont(fontName, 'normal');
        const summaryText = Object.entries(itemSummary)
            .sort((a,b) => a[0].localeCompare(b[0]))
            .map(e => `${e[0]}: ${e[1]}`)
            .join(' | ');

        const sumLines = doc.splitTextToSize(summaryText, pageW - (margin*2));
        doc.text(sumLines, margin, currentY + 10);

        const dateStr = new Date().toISOString().slice(0, 10).replace(/-/g, '');
        doc.save(`DS_${batchId}_${dateStr}.pdf`);
    },

    // --- MODE 2: INVOICE (8-UP) - Unchanged ---
    generateInvoiceBatch: async (orders: Order[], batchId: string) => {
        const doc = new jsPDF({
            orientation: 'p',
            unit: 'mm',
            format: 'a4',
            putOnlyUsedFonts: true,
            floatPrecision: 16
        });

        const binaryFont = await fetchFont();
        let fontName = 'helvetica';

        if (binaryFont) {
            const fontFileName = 'Roboto.ttf';
            doc.addFileToVFS(fontFileName, binaryFont);
            doc.addFont(fontFileName, 'Roboto', 'normal');
            doc.addFont(fontFileName, 'Roboto', 'bold');
            doc.setFont('Roboto');
            fontName = 'Roboto';
        }

        const bankConfig = await storageService.getBankConfig();
        const shopConfig = await storageService.getShopConfig();
        const currentUser = storageService.getCurrentUser() || 'Admin';

        const APP_NAME = (shopConfig?.shopName || "ECOGO LOGISTICS").toUpperCase(); 
        const HOTLINE = shopConfig?.hotline ? `Hotline: ${shopConfig.hotline}` : `User: ${currentUser}`;

        const pageWidth = 210;
        const pageHeight = 297;

        const cols = 2;
        const rows = 4;
        const cellWidth = pageWidth / cols; 
        const cellHeight = pageHeight / rows; 
        const padding = 6; 

        for (let i = 0; i < orders.length; i++) {
            const order = orders[i];

            if (i > 0 && i % 8 === 0) {
                doc.addPage();
                doc.setFont(fontName); 
            }

            const posInPage = i % 8;
            const colIndex = posInPage % 2;
            const rowIndex = Math.floor(posInPage / 2);

            const x = colIndex * cellWidth;
            const y = rowIndex * cellHeight;

            doc.setDrawColor(150, 150, 150);
            doc.setLineWidth(0.1);
            if (colIndex === 0) drawDashedLine(doc, x + cellWidth, y + 2, x + cellWidth, y + cellHeight - 2); 
            if (rowIndex < rows - 1) drawDashedLine(doc, x + 2, y + cellHeight, x + (cellWidth*2) - 2, y + cellHeight);

            const wx = x + padding;
            const wy = y + padding;
            const wWidth = cellWidth - (padding * 2);

            const headerH = 10;
            doc.setFillColor(0, 0, 0); 
            doc.rect(wx, wy, wWidth, headerH, 'F'); 

            doc.setTextColor(255, 255, 255);
            doc.setFontSize(11);
            doc.setFont(fontName, 'bold');
            doc.text(APP_NAME, wx + 2, wy + 6.5);

            doc.setFontSize(8);
            doc.setFont(fontName, 'normal');
            doc.text(HOTLINE, wx + wWidth - 2, wy + 6.5, { align: 'right' });

            doc.setTextColor(0, 0, 0); 

            doc.setFontSize(16);
            doc.setFont(fontName, 'bold');
            doc.setTextColor(200, 200, 200); 
            const seqNo = `#${(i + 1).toString().padStart(2, '0')}`;
            doc.text(seqNo, wx + wWidth - 2, wy + headerH + 7, { align: 'right' });
            doc.setTextColor(0, 0, 0); 

            let cy = wy + headerH + 5;
            doc.setFontSize(12);
            doc.setFont(fontName, 'bold');
            doc.text(`#${order.id}`, wx, cy);

            doc.setFontSize(8);
            doc.setFont(fontName, 'normal');
            doc.text(new Date(order.createdAt).toLocaleDateString('vi-VN'), wx, cy + 4);

            cy += 8;

            doc.setFontSize(9);
            doc.setFont(fontName, 'bold');
            doc.text(order.customerName.toUpperCase(), wx, cy);

            doc.setFont(fontName, 'normal');
            doc.text(order.customerPhone, wx + wWidth - 20, cy, { align: 'right' });

            cy += 4;
            doc.setFontSize(8);
            const addr = order.address.length > 55 ? order.address.substring(0, 52) + "..." : order.address;
            doc.text(`ĐC: ${addr}`, wx, cy);

            cy += 2;
            doc.setDrawColor(0, 0, 0);
            doc.setLineWidth(0.2);
            doc.line(wx, cy, wx + wWidth, cy);
            cy += 4;

            doc.setFontSize(8);
            const MAX_ITEMS = 3; 
            const itemsToShow = order.items.slice(0, MAX_ITEMS);

            itemsToShow.forEach(item => {
                const name = item.name.length > 35 ? item.name.substring(0, 32) + ".." : item.name;
                doc.text(name, wx, cy);

                doc.setFont(fontName, 'bold');
                doc.text(`x${item.quantity}`, wx + wWidth, cy, { align: 'right' });
                doc.setFont(fontName, 'normal');
                cy += 4;
            });

            if (order.items.length > MAX_ITEMS) {
                doc.setFontSize(7);
                doc.text(`... (+${order.items.length - MAX_ITEMS} sản phẩm khác)`, wx, cy);
            }

            if (order.notes) {
                cy += 2;
                doc.setFontSize(7);
                doc.setFont(fontName, 'normal'); 
                doc.text(`Ghi chú: ${order.notes}`, wx, cy);
            }

            const footerY = wy + cellHeight - (padding * 2); 

            const qrSize = 14;
            const qrY = footerY - qrSize;

            if (bankConfig && bankConfig.accountNo && order.paymentMethod !== PaymentMethod.PAID) {
                const content = `DH ${order.id}`;
                const qrString = generateVietQRPayload(bankConfig.bankId, bankConfig.accountNo, order.totalPrice, content);
                const qrBase64 = await generateQRCode(qrString);
                if (qrBase64) {
                    doc.addImage(qrBase64, 'PNG', wx, qrY, qrSize, qrSize);

                    const arrowX = wx + qrSize + 1;
                    const arrowY = qrY + (qrSize / 2);

                    doc.setFontSize(7);
                    doc.setFont(fontName, 'bold');
                    doc.setTextColor(0, 0, 0);

                    doc.text("QUÉT MÃ ĐỂ", arrowX + 5, arrowY - 1);
                    doc.text("THANH TOÁN", arrowX + 5, arrowY + 2);

                    doc.setDrawColor(0, 0, 0);
                    doc.setLineWidth(0.3);
                    doc.line(arrowX + 4, arrowY, arrowX, arrowY); 
                    doc.line(arrowX + 1.5, arrowY - 1.5, arrowX, arrowY); 
                    doc.line(arrowX + 1.5, arrowY + 1.5, arrowX, arrowY); 
                }
            } else if (order.paymentMethod === PaymentMethod.PAID) {
                doc.setDrawColor(0, 0, 0);
                doc.setLineWidth(0.5);
                doc.rect(wx, qrY + 4, 25, 8);
                doc.setFontSize(10);
                doc.setFont(fontName, 'bold');
                doc.text("ĐÃ TT", wx + 12.5, qrY + 9, { align: 'center' });
            }

            doc.setFontSize(16);
            doc.setFont(fontName, 'bold');
            const totalStr = `${new Intl.NumberFormat('vi-VN').format(order.totalPrice)}đ`;
            doc.text(totalStr, wx + wWidth, footerY - 6, { align: 'right' });

            doc.setFontSize(8);
            doc.setFont(fontName, 'normal');
            doc.text("TỔNG THANH TOÁN", wx + wWidth, footerY - 13, { align: 'right' });
        }

        const dateStr = new Date().toISOString().slice(0, 10).replace(/-/g, '');
        doc.save(`HoaDonBW_${batchId}_${dateStr}.pdf`);
    }
};
