                setEditProductMode('IMPORT');
                setViewingProduct(null); 
            }}
            onAdjust={() => {
                setEditingProduct(viewingProduct);
                setEditProductMode('SET');
                setViewingProduct(null);
            }}
          />
      )}

      <ProductEditModal 
          isOpen={!!editingProduct}
          onClose={() => setEditingProduct(null)}
          product={editingProduct}
