                          <button 
                              onClick={() => setReconcileResult(null)}
                              className="w-full py-3 bg-gray-200 hover:bg-gray-300 text-gray-700 font-bold rounded-xl transition-all"
                          >
                              Thử lại file khác
                          </button>
                      </div>
                  )}
              </div>
          </div>
      )}

      {/* BULK STATUS UPDATE MODAL */}
