```javascript
const CACHE_NAME = 'ecogo-cache-v60';
const urlsToCache = [
  '/',
  '/index.html',
  '/manifest.json'
];

self.addEventListener('install', (event) => {
  self.skipWaiting();
  event.waitUntil(
    caches.open(CACHE_NAME)
      .then((cache) => {
        return cache.addAll(urlsToCache);
      })
  );
});

self.addEventListener('fetch', (event) => {
  if (event.request.mode === 'navigate') {
    event.respondWith(
      fetch(event.request).catch(() => caches.match(event.request))
    );
    return;
  }
  event.respondWith(
    caches.match(event.request).then((response) => response || fetch(event.request))
  );
});

self.addEventListener('activate', (event) => {
  const cacheWhitelist = [CACHE_NAME];
  event.waitUntil(
    Promise.all([
      caches.keys().then((cacheNames) => {
        return Promise.all(
          cacheNames.map((cacheName) => {
            if (cacheWhitelist.indexOf(cacheName) === -1) {
              return caches.delete(cacheName);
            }
          })
        );
      }),
      self.clients.claim()
    ])
  );
});

Để khắc phục lỗi TypeScript `TS2322` khi build (`npm run build`), nguyên nhân là do tên props `onDragStart` của component `OrderCard` (nhận 2 tham số: event và index) trùng tên với sự kiện DOM chuẩn `onDragStart` (chỉ nhận 1 tham số là event). Điều này gây nhầm lẫn cho trình biên dịch TypeScript khi kiểm tra kiểu dữ liệu.

Giải pháp triệt để là **đổi tên props** trong `OrderCard` để tránh trùng lặp. Tôi sẽ đổi `onDragStart` thành `onRowDragStart` và `onDragEnter` thành `onRowDragEnter`.

