            doc.addFont(fontFileName, 'Roboto', 'normal');
            doc.addFont(fontFileName, 'Roboto', 'bold');
            doc.addFont(fontFileName, 'Roboto', 'italic');
            doc.setFont('Roboto');
            fontName = 'Roboto';
        }

        // --- PAGE CONFIG ---
        const pageW = 210;
        const pageH = 297;
        const margin = 5; 
        const headerH = 10; // Slim header
        const tableW = pageW - (margin * 2); // 200mm

        // --- COLUMN WIDTHS (Total 200mm) ---
        // 1. STT: 7mm
        // 2. Tên: 35mm
        // 3. SĐT: 22mm
        // 4. Địa chỉ: 50mm
        // 5. Hàng hóa (Tên + SL): 45mm
        // 6. Ghi chú: 21mm
        // 7. Tiền/TT: 20mm

        const wIdx = 7;
        const wName = 35;
        const wPhone = 22;
        const wAddr = 50;
        const wItem = 45;
        const wNote = 21;
        const wPrice = tableW - wIdx - wName - wPhone - wAddr - wItem - wNote; // ~20mm

        // X Positions
        const xIdx = margin;
        const xName = xIdx + wIdx;
        const xPhone = xName + wName;
        const xAddr = xPhone + wPhone;
        const xItem = xAddr + wAddr;
        const xNote = xItem + wItem;
        const xPrice = xNote + wNote;

        let currentY = headerH + 3;

        // --- HIGH DENSITY SETTINGS ---
        const fontSize = 7; // Small font
        const rowPadding = 1; // 1mm padding
        const lineHeight = 3; // 3mm per text line

        // Data Prep
        let totalAmount = 0;
        const itemSummary: Record<string, number> = {};

        const validOrders = orders.filter(o => o.status !== OrderStatus.CANCELLED);
        validOrders.forEach(o => {
            totalAmount += o.totalPrice;
            o.items.forEach(item => {
                const name = item.name.trim();
                if(name) itemSummary[name] = (itemSummary[name] || 0) + item.quantity;
            });
        });

        const drawPageHeader = (pageNo: number) => {
            doc.setFillColor(255, 255, 255);
            doc.rect(0, 0, pageW, headerH, 'F');

            // Doc Title
            doc.setFontSize(10);
            doc.setFont(fontName, 'bold');
            doc.setTextColor(0, 0, 0);
            doc.text(`${batchId} - ${new Date().toLocaleDateString('vi-VN')}`, margin, 5);

            doc.setFontSize(7);
            doc.setFont(fontName, 'normal');
            doc.text(`Trang ${pageNo}`, pageW - margin, 5, { align: 'right' });

            // --- TABLE HEADER (BLACK BG) ---
            const hY = 7;
