            doc.line(xPhone, hY, xPhone, hY + hHeight);
            doc.line(xAddr, hY, xAddr, hY + hHeight);
            doc.line(xItem, hY, xItem, hY + hHeight);
            doc.line(xNote, hY, xNote, hY + hHeight);
            doc.line(xPrice, hY, xPrice, hY + hHeight);

            // Text
