            const cleanAddr = o.address.replace(/^(số|nhà|đường|hẻm|ngõ)\s/gi, '');
            const addrLines = doc.splitTextToSize(cleanAddr, wAddr - 1);

            // 4. Items (Normal)
            doc.setFont(fontName, 'normal');
            const itemsStr = o.items.map(it => `${it.name}${it.quantity > 1 ? ` (${it.quantity})` : ''}`).join(', ');
            const itemsLines = doc.splitTextToSize(itemsStr, wItem - 1);

            // 5. Note (Italic)
            const noteText = o.notes || '';
            const noteLines = doc.splitTextToSize(noteText, wNote - 1);

