            const maxLines = Math.max(nameLines.length, addrLines.length, itemsLines.length, noteLines.length, statusText ? 2 : 1);
            const rowHeight = Math.max(4.5, (maxLines * lineHeight) + (rowPadding * 2));

            // Check Page Break
            if (currentY + rowHeight > pageH - 8) {
                doc.addPage();
                pageIndex++;
                currentY = drawPageHeader(pageIndex);
            }

            // --- DRAW ROW ---
            const textY = currentY + rowPadding + 2.5;

