            onTouchStart={onTouchStart}
            onTouchMove={onTouchMove}
            onTouchEnd={onTouchEnd}
            onDragStart={(e) => { if (onRowDragStart && index !== undefined) onRowDragStart(e, index); }}
            onDragEnter={(e) => { if (onRowDragEnter && index !== undefined) onRowDragEnter(e, index); }}
            onDragEnd={onDragEnd}
            onDragOver={onDragOver}
            draggable={true}
          >
             <i className="fas fa-grip-vertical text-lg"></i>
          </div>
