  const config = statusConfig[order.status];
  const isCompleted = order.status === OrderStatus.DELIVERED || order.status === OrderStatus.CANCELLED;

  const PaymentBadge = ({ compact = false }: { compact?: boolean }) => {
    const showText = isCompleted || order.paymentVerified || order.paymentMethod === PaymentMethod.PAID;

    if (!showText && compact) return null;

    if (!showText && !compact) {
         return (
             <button onClick={(e) => { e.stopPropagation(); requestQR(e); }} className="text-blue-600" aria-label="Hiện mã QR">
                 <i className="fas fa-qrcode"></i>
             </button>
         );
    }

    const isTransfer = order.paymentMethod === PaymentMethod.TRANSFER;
    let text = '', style = '';

    if (order.paymentMethod === PaymentMethod.CASH) { 
        text = 'Tiền mặt'; 
        style = 'text-gray-500 bg-gray-50 border-gray-200'; 
    } else if (order.paymentMethod === PaymentMethod.PAID) { 
        text = 'Đã TT'; 
        style = 'text-green-700 bg-green-50 border-green-100'; 
    } else { 
        text = order.paymentVerified ? 'Đã nhận' : 'Chờ CK'; 
        style = order.paymentVerified ? 'text-green-700 bg-green-50 border-green-100 cursor-pointer' : 'text-blue-600 bg-blue-50 border-blue-100 cursor-pointer'; 
    }

    return (
        <div 
            className="flex items-center gap-1" 
            onClick={(e) => { if (isTransfer) { e.stopPropagation(); togglePaymentVerification(); } }}
        >
            <span className={`text-[9px] font-bold px-1.5 py-0.5 rounded border whitespace-nowrap ${style}`}>
                {text}
            </span>
            {(!isCompleted && !order.paymentVerified) && (
                <button onClick={requestQR} className="text-blue-600 ml-0.5" aria-label="Hiện mã QR">
                    <i className="fas fa-qrcode text-[10px]"></i>
                </button>
            )}
        </div>
    );
  };

  const CheckboxOverlay = () => { if (!isSelectionMode) return null; return (<div className={`absolute top-0 bottom-0 left-0 w-1.5 ${isSelected ? 'bg-eco-500' : 'bg-transparent'}`}></div>); }

  const SelectTrigger = ({ compact = false }) => {
    if (isSelectionMode) {
        return (
            <div className={`w-5 h-5 rounded border flex items-center justify-center transition-all ${compact ? '' : 'mr-3'} flex-shrink-0 ${isSelected ? 'bg-eco-500 border-eco-500 text-white' : 'border-gray-300 bg-white'}`}>
                <i className="fas fa-check text-[10px]"></i>
            </div>
        );
    }
    return (
         <div 
